class BookModel {
  final String title, auth, image;

  BookModel({required this.title, required this.auth, required this.image});

  factory BookModel.fromJson(Map<String, dynamic> json) {
    return BookModel(
      title: json['docs']['title'],
      auth: json['docs']['author_name'] ?? 'No author available',
      image: json['docs']['cover_i'] != null
          ? 'https://covers.openlibrary.org/b/id/${json['docs'][0]['cover_i']}-M.jpg'
          : 'No image available',
    );
  }
}
